#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e6+5;
PII a[MAXN],b[MAXN];
int n,m,x,ans;
priority_queue<int> q;
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n>>m;
    FOR(i,1,n)
    {
        cin>>a[i].fst>>a[i].snd;
    }
    FOR(i,1,m)
    {
        cin>>b[i].fst>>b[i].snd;
    }
    sort(a+1,a+n+1);
    sort(b+1,b+m+1);
	FOR(i,1,n)
	{
        wh(x<=m&&b[x].fst<=a[i].fst)
        {
            q.push(b[x].snd);
			++x;
        }
        if(q.empty()||a[i].fst-a[i].snd>q.top())
		{
			ans+=a[i].snd;
		}
        else
        {
            ans+=a[i].fst-q.top();
            q.pop();
            q.push(a[i].fst-a[i].snd);
        }
	}
	cout<<ans;
    return false;
}
